  ('pukao-64311456-moex-00039', 'pukao-64311456', 'pukao-64311456-moex-114-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '有關英國學者季登斯（A.Giddens）所提之第三條路論述，下列何者正確？', '["作為福利國家應從搖籃到墳墓的保護人民", "政府補助多元的供給者", "福利是扮演最後一道防線", "政府應提高福利普及性的承諾"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "9bac9cd4d224", "answer_pdf_sha1": "a8daa8efff43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00040', 'pukao-64311456', 'pukao-64311456-moex-114-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '有關我國社會福利基本法之福利事項內容，下列何者不是該法所稱之福利事項？', '["醫療保健", "國民就業", "社會住宅", "社會教育"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "9bac9cd4d224", "answer_pdf_sha1": "a8daa8efff43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00041', 'pukao-64311456', 'pukao-64311456-moex-114-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '有關全民健康保險法的規定，下列敘述何者正確？', '["本保險對象包括最近一年內曾參加本保險紀錄且在臺灣地區設有戶籍者", "本保險費率之審議由主管機關衛生福利部辦理", "政府每年度負擔本保險之總經費，不得少於每年度保險經費扣除法定收入後金額之百分之三十", "第三類被保險人包括農會會員或年滿十五歲以上實際從事農業工作者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "9bac9cd4d224", "answer_pdf_sha1": "a8daa8efff43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00042', 'pukao-64311456', 'pukao-64311456-moex-114-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '依據我國社會救助法之規定，下列敘述何者錯誤？', '["中低收入戶之家庭總收入平均分配全家人口，每人每月不超過最低生活費一點五倍者", "低收入戶所定家庭財產，包括動產及不動產，其金額應合併定之", "最低生活費乃參照中央主計機關所公布當地區最近一年每人可支配所得中位數百分之六十定之", "家庭應計算人口範圍之規定中，在學領有公費者不列入應計算人口範圍"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "9bac9cd4d224", "answer_pdf_sha1": "a8daa8efff43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00043', 'pukao-64311456', 'pukao-64311456-moex-114-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '阿福有一群好友皆已年滿29歲，正處於轉職期。依據兒童及少年福利與權益保障法之規定，下列 那一位尚不符合居家式托育服務提供者之資格？', '["小恩：高中畢業，取得保母人員技術士證", "小美：畢業於某大學護理學系，並未修習托育人員專業訓練課程", "小琪：已修畢托育人員專業訓練課程，並領有結業證書", "小琳：畢業於某大學心理學系，正在修習托育人員專業訓練課程"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "9bac9cd4d224", "answer_pdf_sha1": "a8daa8efff43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00044', 'pukao-64311456', 'pukao-64311456-moex-114-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '依據兒童及少年福利與權益保障法之規定，下列有關收出養之敘述，何者錯誤？', '["從事收出養媒合服務，以經主管機關許可之財團法人、公私立兒童及少年安置、教養機構為限", "收出養媒合服務者應評估並安排收養人與兒童、少年先行共同生活或漸近式接觸", "父母對於兒童及少年出養之意見不一致，或一方所在不明時，父母之一方仍可向法院聲請認可", "收出養媒合服務者從事收出養媒合服務，得向出養人收取服務費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "9bac9cd4d224", "answer_pdf_sha1": "a8daa8efff43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00045', 'pukao-64311456', 'pukao-64311456-moex-114-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '依據我國兒童及少年性剝削防制條例之規定，有關性剝削案件被害人之安置及服務，下列敘述何 者正確？', '["被害人經安置後，主管機關應每月進行評估，並最遲於安置期滿三十日前，向法院提出評估報告", "經評估有繼續安置之必要者，應於安置期滿四十五日前，向法院提出評估報告，聲請法院裁定 延長安置，其每次延長之期間不得逾一年", "聲請法院裁定延長安置，以延長至被害人年滿十八歲為止", "經法院裁定無安置必要者，主管機關應指派社會工作人員進行輔導處遇，期間至少二年或至其 年滿二十歲止"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "9bac9cd4d224", "answer_pdf_sha1": "a8daa8efff43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00046', 'pukao-64311456', 'pukao-64311456-moex-114-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '依據我國身心障礙者權益保障法之規定，下列何者不是身心障礙福利經費的來源？', '["社會福利基金", "身心障礙者就業基金", "特別教育捐", "私人或團體捐款"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "9bac9cd4d224", "answer_pdf_sha1": "a8daa8efff43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00047', 'pukao-64311456', 'pukao-64311456-moex-114-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '性侵害犯罪防治法有關預防及通報之規定，下列敘述何者錯誤？', '["高級中等以下學校每學年應實施性侵害防治教育課程，至少二小時", "主管機關及目的事業主管機關應就其權責範圍，依性侵害防治之需要，尊重多元文化差異，主 動規劃預防、宣導等必要措施", "性侵害防治教育課程，應包括性侵害防範之技巧", "幼兒園應實施性侵害防治教育宣導"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "9bac9cd4d224", "answer_pdf_sha1": "a8daa8efff43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL)
